const trips = $input.first().json.result || [];
const idleVehicles = [];
for (const trip of trips) {
  const idle = trip.idlingDuration || 'PT0S';
  const match = idle.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+(?:\.\d+)?)S)?/);
  if (match) {
    const mins = (parseInt(match[1]||0)*60) + parseInt(match[2]||0) + parseFloat(match[3]||0)/60;
    if (mins > 30) {
      idleVehicles.push({ device: trip.device?.id, idleMinutes: Math.round(mins), distance: (trip.distance/1000).toFixed(1) });
    }
  }
}
return [{ json: { idleVehicles, count: idleVehicles.length } }];
